import{_ as a,o as l,c as i,ag as e}from"./chunks/framework.DL-RKwfR.js";const _=JSON.parse('{"title":"员工快速上手","description":"","frontmatter":{"title":"员工快速上手","category":"-快速上手","order":4,"lastUpdated":"2026-03-15T04:31:45.482Z"},"headers":[],"relativePath":"-快速上手/员工快速上手.md","filePath":"-快速上手/员工快速上手.md"}'),t={name:"-快速上手/员工快速上手.md"};function r(o,p,s,n,h,d){return l(),i("div",null,[...p[0]||(p[0]=[e('<h1 id="员工快速上手" tabindex="-1">员工快速上手 <a class="header-anchor" href="#员工快速上手" aria-label="Permalink to &quot;员工快速上手&quot;">​</a></h1><h1 id="使用说明" tabindex="-1">使用说明 <a class="header-anchor" href="#使用说明" aria-label="Permalink to &quot;使用说明&quot;">​</a></h1><h2 id="step-1-部门管理员发送邀请二维码海报" tabindex="-1">Step 1：部门管理员发送邀请二维码海报 <a class="header-anchor" href="#step-1-部门管理员发送邀请二维码海报" aria-label="Permalink to &quot;Step 1：部门管理员发送邀请二维码海报&quot;">​</a></h2><ol><li><p>进入xx企业版 tab</p></li><li><p>【邀请成员】入口仅管理员可见</p></li><li><p>点击【邀请成员加入企业】入口，去生成邀请二维码</p></li><li><p>下方列表展示已加入成员信息，可以点【删除】来将员工移出企业</p></li><li><p>将邀请二维码保存到手机，并发给员工</p></li><li><p>员工微信扫码加入</p></li><li><p>二维码有效期为 3 天，过期后需重新生成</p></li></ol><h3 id="企业的部门管理员是谁" tabindex="-1">企业的部门管理员是谁 <a class="header-anchor" href="#企业的部门管理员是谁" aria-label="Permalink to &quot;企业的部门管理员是谁&quot;">​</a></h3><p>想加入对应部门下，请找企业或部门管理员要邀请二维码海报。</p><p><strong>部门</strong></p><p><strong>层级</strong></p><p><strong>管理员</strong></p><p>Xxx 运营中心</p><p>A 企业/xxx运营中心</p><p>杨总</p><p>Xxx 美学中心</p><p>A 企业/xxx美学中心</p><p>李总</p><h2 id="step-2-员工扫码加入企业" tabindex="-1">Step 2：员工扫码加入企业 <a class="header-anchor" href="#step-2-员工扫码加入企业" aria-label="Permalink to &quot;Step 2：员工扫码加入企业&quot;">​</a></h2><ol><li><p>点击管理员发的邀请二维码海报</p></li><li><p>识别二维码</p></li><li><p>填写员工姓名，选择部门</p></li><li><p>选择所属团队</p></li><li><p>点击立刻加入企业</p></li><li><p>加入成功后点击进入企业</p></li><li><p>中间 tab 展示为对应企业，即可开始使用</p></li></ol><h2 id="step-3-员工开始练习场景" tabindex="-1">Step 3：员工开始练习场景 <a class="header-anchor" href="#step-3-员工开始练习场景" aria-label="Permalink to &quot;Step 3：员工开始练习场景&quot;">​</a></h2><ol><li><p>选择要练习的场景，点击进入</p></li><li><p>了解场景练习目标等信息，开始练习</p></li><li><p>点击开始说明，和 AI 进行对话</p></li><li><p>说话完成后，点击确认发送</p></li><li><p>不知道说什么，可以点击对话灵感，给出参考话术</p></li><li><p>点击改进建议，可以查看单句的建议和润色</p></li><li><p>点击结束按钮，选择查看测评报告，可以去看详细测评分析</p></li><li><p>AI 分析需要一些时间（1-2分钟），可以选“生成后通知我”，生成后会以小程序消息通知</p></li><li><p>生成的报告会从说服力、流利度等多个维度进行评价打分</p></li><li><p>重点关注说服力维度，这里是练习的核心部分</p></li><li><p>点击顶部，可以在报告和对话过程间切换</p></li></ol><h2 id="step-4-查看历史练习记录" tabindex="-1">Step 4：查看历史练习记录 <a class="header-anchor" href="#step-4-查看历史练习记录" aria-label="Permalink to &quot;Step 4：查看历史练习记录&quot;">​</a></h2><ol><li><p>选择【练习记录】，可以查看全部练习记录信息</p></li><li><p>点击任意练习记录，可以去到报告页查看测评结果</p></li><li><p>没有分数的练习记录，说明结束时未生成练习报告，重新进入生成即可</p></li><li><p>排行榜可以查看所在部门的同事练习排名</p></li><li><p>可以按时间、场景、排名方式（分数/时长）等查看</p></li></ol><h1 id="其它常见问题-q-a" tabindex="-1">其它常见问题 Q&amp;A <a class="header-anchor" href="#其它常见问题-q-a" aria-label="Permalink to &quot;其它常见问题 Q&amp;A&quot;">​</a></h1><p><strong>Q：练习报告半天没有生成结果，比较慢。</strong></p><p>A：练习报告生成一般在 1-3 分钟内，如果超过 10 分钟没有生成，可以去【我的-问题反馈】中，联系我们反馈问题。</p><p><strong>Q：加入企业时，提示没成功，怎么办？</strong></p><p>A：有可能是邀请的二维码过期了，二维码默认是 3 天的有效期，如果过期了，可以找管理员再发一个最新的邀请二维码。</p>',26)])])}const x=a(t,[["render",r]]);export{_ as __pageData,x as default};
